<template>
  <div
    :class="
      'sticky sm:static sm:mt-4 sm:mb-3 pt-4 sm:pt-0 top-12 z-10 ' +
      'flex flex-wrap items-center justify-center w-full sm:h-44'
    "
    style="background-color: #f9f8fd"
  >
    <div
      v-for="i in 6"
      :key="i"
      class="inline-block relative m-0.5 support-card"
      :style="{ width: 'calc((100% - 28px) / 6)', 'max-width': '90px' }"
    >
      <support-card
        v-if="cards[i - 1] != null"
        :id="cards[i - 1].detail.id"
        :rarity="cards[i - 1].detail.rarity"
        :type="cards[i - 1].detail.command_id"
        :diamond="cards[i - 1].diamond"
        :level="cards[i - 1].level"
        :absolute="true"
        width="100%"
        @click="updateCard(i - 1)"
      />
      <div
        v-else
        class="absolute cursor-pointer shadow-inner rounded-lg border-2 border-gray-300"
        :style="{
          width: 100 * (87 / 90) + '%',
          height: 100 * (87 / 90) + '%',
          left: 100 * (1.5 / 90) + '%',
          top: 100 * (1 / 90) + '%',
        }"
        @click="updateCard(i - 1)"
      >
        <img
          :src="`${publicPath}img/icon/utx_ico_plus_00.png`"
          class="absolute left-1/2 top-1/2"
          :style="{ width: '24%', transform: 'translate(-50%, -50%)' }"
        />
      </div>
    </div>

    <!-- Reset button -->
    <div class="flex items-center sm:h-12 mt-2 sm:mt-1 mb-3 sm:mb-0">
      <button
        :class="
          'hover:bg-gray-100 border border-gray-600 rounded-xl shadow ' +
          'px-3 sm:px-4 py-0.5 sm:py-1 text-xs sm:text-sm'
        "
        @click="resetDeck"
      >
        デッキをリセット
      </button>
    </div>
  </div>

  <!-- Stats -->
  <div
    v-for="statIndex in 17"
    :key="statIndex"
    class="flex flex-wrap items-center w-full h-10 sm:h-8 text-xs sm:text-base"
    :class="statIndex % 2 === 1 ? 'bg-gray-200' : ''"
  >
    <div class="sm:hidden flex items-center justify-center w-full h-5 sm:h-auto text-xs font-bold">
      {{
        [
          "友情ボーナス",
          "やる気効果アップ",
          "トレーニングボーナス",
          "トレーニング効果アップ",
          "初期ステータス値アップ",
          "初期絆ゲージアップ",
          "レースボーナス",
          "ファン数ボーナス",
          "ヒントLvアップ",
          "ヒント発生率アップ",
          "得意率アップ",
          "イベント回復量アップ",
          "イベント効果アップ",
          "失敗率ダウン",
          "体力消費ダウン",
          "スキルPtボーナス",
          "賢さ友情回復量アップ",
        ][statIndex - 1]
      }}
    </div>
    <div
      class="hidden sm:block flex-grow h-full"
      :style="left ? 'background-color: #f9f8fd' : ''"
    />
    <div
      v-for="cardIndex in 6"
      :key="cardIndex"
      class="flex mx-0.5 items-center justify-center h-5 sm:h-auto"
      :style="{ width: 'calc((100% - 28px) / 6)', 'max-width': '90px' }"
    >
      <div class="flex items-center" v-if="cardStats[cardIndex - 1] != null">
        <img
          v-for="iconId in cardStats[cardIndex - 1][statIndex - 1].icon"
          :key="iconId"
          :src="`${publicPath}img/icon/utx_ico_obtain_0${iconId}.png`"
          class="mr-0.5 sm:mr-1 w-4 sm:w-5"
        />
        <span>{{ cardStats[cardIndex - 1][statIndex - 1].text }}</span>
      </div>
    </div>
    <div
      class="hidden sm:block flex-grow h-full"
      :style="!left ? 'background-color: #f9f8fd' : ''"
    />
  </div>

  <!-- Modal -->
  <add-support-modal
    v-model:show="showModal"
    v-model:cards="cards"
    v-model:deckIndex="selectedIndex"
    @select="select"
  />
</template>

<script lang="ts">
import { defineComponent } from "vue";
import AddSupportModal from "./AddSupportModal.vue";
import SupportCard from "./SupportCard.vue";
import SupportCardJson from "@/assets/support_card_data.json";

type CardInfo = { detail: typeof SupportCardJson[number]; diamond: number; level: number };

export default defineComponent({
  components: {
    AddSupportModal,
    SupportCard,
  },

  data: function () {
    let cards: (CardInfo | null)[] = [null, null, null, null, null, null];
    return {
      cards,
      selectedIndex: 0,
      showModal: false,
      publicPath: process.env.BASE_URL,
    };
  },

  props: {
    left: {
      type: Boolean,
      required: true,
    },
  },

  computed: {
    cardStats: function (): ({ icon: number[]; text: string }[] | null)[] {
      let stats: ({ icon: number[]; text: string }[] | null)[] = [];

      for (const card of this.cards) {
        // null
        if (card == null) {
          stats.push(null);
          continue;
        }

        let effectArray = new Array<number>(32).fill(0);

        // support effects
        for (const supportEffect of card.detail.effect) {
          let lo = { lv: -1, value: -1 };
          let hi = { lv: -1, value: -1 };

          for (let i = card.level / 5; i >= 0; --i) {
            if (supportEffect.value[i] !== -1) {
              lo = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          for (let i = card.level / 5; i <= 10; ++i) {
            if (supportEffect.value[i] !== -1) {
              hi = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          if (lo.value === -1) {
            // do nothing
          } else if (hi.value === -1 || lo.lv == hi.lv) {
            effectArray[supportEffect.type] = lo.value;
          } else {
            const v = lo.value + ((card.level - lo.lv) * (hi.value - lo.value)) / (hi.lv - lo.lv);
            effectArray[supportEffect.type] = Math.floor(v);
          }
        }

        // unique effects
        if (card.detail.unique != null && card.level >= card.detail.unique.lv) {
          for (const uniqueEffect of card.detail.unique.effect) {
            const ty = uniqueEffect.type;
            if ([1, 19].includes(ty) && effectArray[ty] !== 0) {
              // 友情ボーナス / 得意率
              const v = ((100 + effectArray[ty]) * (100 + uniqueEffect.value) - 10000) / 100;
              effectArray[ty] = v;
            } else {
              effectArray[ty] += uniqueEffect.value;
            }
          }
        }

        let stat: { icon: number[]; text: string }[] = [];
        const effectPer = [1, 2, 8, 15, 16, 18, 25, 26, 27, 28];
        const defaultPush = (index: number) => {
          const text =
            effectArray[index] === 0
              ? "-"
              : (effectPer.includes(index) ? "" : "+") +
                effectArray[index].toString() +
                (effectPer.includes(index) ? "%" : "");
          stat.push({ icon: [], text });
        };

        defaultPush(1); // 友情
        defaultPush(2); // やる気

        // 練習ボーナス
        let trainingBonus: { icon: number[]; text: string } | null = null;
        for (let i = 3; i < 8; ++i) {
          if (effectArray[i] > 0) {
            if (trainingBonus == null) {
              trainingBonus = { icon: [i - 3], text: "+" + effectArray[i].toString() };
            } else {
              if (trainingBonus.text !== "+" + effectArray[i].toString()) {
                trainingBonus = { icon: [], text: "Error!" };
                break;
              }
              trainingBonus.icon.push(i - 3);
            }
          }
        }
        stat.push(trainingBonus ?? { icon: [], text: "-" });

        defaultPush(8); // トレ効果

        // 初期ボーナス
        let initialBonus: { icon: number[]; text: string } | null = null;
        for (let i = 9; i < 14; ++i) {
          if (effectArray[i] > 0) {
            if (initialBonus == null) {
              initialBonus = { icon: [i - 9], text: "+" + effectArray[i].toString() };
            } else {
              if (initialBonus.text !== "+" + effectArray[i].toString()) {
                initialBonus = { icon: [], text: "Error!" };
                break;
              }
              initialBonus.icon.push(i - 9);
            }
          }
        }
        stat.push(initialBonus ?? { icon: [], text: "-" });

        defaultPush(14); // 初期絆
        defaultPush(15); // レース
        defaultPush(16); // ファン数
        defaultPush(17); // ヒントLv
        defaultPush(18); // ヒント発生率
        defaultPush(19); // 得意率
        defaultPush(25); // イベ回復量
        defaultPush(26); // イベ効果
        defaultPush(27); // 失敗率
        defaultPush(28); // 体力消費
        defaultPush(30); // スキルPt
        defaultPush(31); // 賢さ友情回復量

        stats.push(stat);
      }

      return stats;
    },
  },

  methods: {
    updateCard: function (index: number) {
      this.selectedIndex = index;
      this.showModal = true;
    },

    select: function (arg: CardInfo) {
      this.cards[this.selectedIndex] = arg;
    },

    resetDeck: function () {
      this.cards = [null, null, null, null, null, null];
    },
  },
});
</script>

<style scoped lang="scss">
.support-card::before {
  content: "";
  display: block;
  padding-top: (66200% / 512);
}
</style>
